INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0305600F$$, 2026, $$International Intelligence Technology and Architectures (IITA) oversees, manages, and provides the United States (US) component of the multi-national Battlefield
Information Collection and Exploitation Systems (BICES) with a collaborative environment and intelligence sharing enterprise required for processing and disseminating
critical intelligence information between and among US, North Atlantic Treaty Organization (NATO), allied and coalition forces. The US BICES program develops and
tests specialized equipment to deliver a more mature, robust and dynamic suite of capabilities for intelligence information sharing across the US BICES, US BICES
Extended (US BICES-X), and the Trusted Network Environment (TNE). US BICES-X is a multi-level, secure system that uses releasable elements of the Defense
Intelligence Information Enterprise (DI2E) framework, and functions to support the full spectrum of intelligence operations and dissemination across Department of
Defense (DoD), Combat Support Agencies (CSA), and multiple Combatant Commands (CCMD) for the Office of the Under Secretary of Defense, Intelligence and
Security (OUSD(I&S)). The TNE is an Enterprise Cross Domain Solution (ECDS) that connects 65+ network, 85+ partner nations and 69+ Communities of Interest (COI)
within four federated operational TNEs. US BICES/BICES-X has been designated the enduring intelligence and information sharing component to the Mission Partner
Environment (MPE).

 Research and Development funding will:
 - Provide increased intelligence information sharing capabilities to US and Coalition forces utilizing the US BICES and multinational BICES networks through CENTAUR.
 CENTAUR provides geospatial intelligence from the Distributed Common Ground System (DGCS) Enterprise to enable Coalition partner operations on multinational
 BICES.
 -Continue developing the TNE as an ECDS that connects 65+ network, 85+ partner nations and 69+ COI within four federated operational TNE service centers and
 supporting all CCMDs, CSAs, and Services.
 - Provide increased intelligence information sharing capabilities in support of US and coalition forces utilizing the US BICES and NATO virtual networks within all
 theaters of operations and provide increased database information sharing.
 - Continue to develop the US BICES connections with bi-lateral and multi-lateral federated TNEs that make up the US BICES-X Enterprise Network in support of
 CCMD requirements for conventional and coalition operations. To include multi-level security intelligence bi-laterals and multi-laterals to meet Combatant Commander
 Integrated Priority Lists.

